(995,1,1,'mcq','S2/SS2','Introduction To Physical Safety Risks When Using Computers',1,'easy',1,1,'What is a physical safety risk when using computers?','It refers to harm to the body caused by improper computer use.',1),
(996,1,1,'mcq','S2/SS2','Musculoskeletal Disorders (MSDs)',1,'easy',1,1,'Musculoskeletal disorders affect which part of the body?','They affect muscles, bones, and joints.',1),
(997,1,1,'mcq','S2/SS2','Causes of Musculoskeletal Problems',1,'easy',1,1,'What is a major cause of musculoskeletal problems when using a computer?','Poor sitting posture.',1),
(998,1,1,'mcq','S2/SS2','Repetitive Strain Injury (RSI)',1,'easy',1,1,'What does RSI stand for?','Repetitive Strain Injury.',1),
(999,1,1,'mcq','S2/SS2','Causes of RSI',1,'easy',1,1,'Which activity can cause RSI?','Typing continuously without breaks.',1),
(1000,1,1,'mcq','S2/SS2','Preventive Measures for RSI',1,'easy',1,1,'How can RSI be prevented?','By taking regular breaks.',1),
(1001,1,1,'mcq','S2/SS2','Vision Problems',1,'easy',1,1,'What is a common vision problem from computer use?','Eye strain.',1),
