INSERT INTO questions (id,school_id,author_id,type,sub_strand,topic,bloom_level,difficulty,year_group,marks,question_text,explanation,is_active) VALUES
(1035,1,1,'mcq','S2/SS2','Musculoskeletal Disorders (MSDs)',2,'medium',1,1,'Which posture is most likely to lead to musculoskeletal disorders when using a computer?','Slouching places strain on the spine and muscles.',1),
(1036,1,1,'mcq','S2/SS2','Ergonomics',2,'medium',1,1,'Why is ergonomics important in a computer workspace?','It reduces physical strain and improves comfort.',1),
(1037,1,1,'mcq','S2/SS2','Causes of RSI',2,'medium',1,1,'Which of the following best explains how RSI develops?','It develops from repeated movements over time without rest.',1),
(1038,1,1,'mcq','S2/SS2','Preventive Measures for RSI',2,'medium',1,1,'Which action best helps to prevent RSI during long computer sessions?','Taking frequent breaks and stretching.',1),
(1039,1,1,'mcq','S2/SS2','Vision Problems',2,'medium',1,1,'Why does staring at a screen for long periods cause eye strain?','Because blinking reduces and eyes dry out.',1),
(1040,1,1,'mcq','S2/SS2','Lighting',2,'medium',1,1,'How does poor lighting contribute to computer-related health problems?','It forces the eyes to work harder.',1),
(1041,1,1,'mcq','S2/SS2','Monitor Position',2,'medium',1,1,'What is the recommended monitor distance from the eyes?','About an arm’s length away.',1),
(1042,1,1,'mcq','S2/SS2','Headaches and Vertigo',2,'medium',1,1,'Which factor is most likely to cause dizziness when using a computer?','Screen flickering or glare.',1),
(1043,1,1,'mcq','S2/SS2','Sleep Disorders',2,'medium',1,1,'Why can using computers late at night affect sleep?','Blue light interferes with sleep hormones.',1),
(1044,1,1,'mcq','S2/SS2','Weight Problems',2,'medium',1,1,'How does prolonged computer use contribute to weight gain?','It reduces physical activity levels.',1),
(1045,1,1,'mcq','S2/SS2','Depression and Anxiety',2,'medium',1,1,'Which behaviour related to computer use may increase anxiety?','Excessive social media use.',1),
(1046,1,1,'mcq','S2/SS2','Trips and Falls',2,'medium',1,1,'What is the best way to reduce trips caused by computer cables?','Organize and secure cables properly.',1),
(1047,1,1,'mcq','S2/SS2','Electrocution Hazards',2,'medium',1,1,'Which condition increases the risk of electrocution in a computer lab?','Using equipment with wet hands.',1),
(1048,1,1,'mcq','S2/SS2','Fire Hazards',2,'medium',1,1,'What is a common cause of electrical fires in computer labs?','Overloading power outlets.',1),
(1049,1,1,'mcq','S2/SS2','Posture',2,'medium',1,1,'Which seating position is ergonomically correct?','Back straight with feet flat on the floor.',1),
(1050,1,1,'mcq','S2/SS2','Keyboard Use',2,'medium',1,1,'Why should wrists be kept straight when typing?','To reduce strain on tendons.',1),
(1051,1,1,'mcq','S2/SS2','Mouse Usage',2,'medium',1,1,'Which practice reduces strain when using a mouse?','Using a mouse pad with wrist support.',1),
(1052,1,1,'mcq','S2/SS2','Breaks',2,'medium',1,1,'What is the 20-20-20 rule related to?','Reducing eye strain.',1),
(1053,1,1,'mcq','S2/SS2','Vision Care',2,'medium',1,1,'Which habit improves eye health during computer use?','Looking away from the screen regularly.',1),
(1054,1,1,'mcq','S2/SS2','Workspace Design',2,'medium',1,1,'Why should the keyboard be positioned at elbow height?','To maintain a natural arm position.',1),
(1055,1,1,'mcq','S2/SS2','Fatigue',2,'medium',1,1,'What is a common sign of computer-related fatigue?','Reduced concentration.',1),
(1056,1,1,'mcq','S2/SS2','Exercise',2,'medium',1,1,'Why is exercise important for computer users?','It improves circulation and reduces stiffness.',1),
(1057,1,1,'mcq','S2/SS2','Stretching',2,'medium',1,1,'Which body part benefits most from stretching during computer use?','Neck and shoulders.',1),
(1058,1,1,'mcq','S2/SS2','Hydration',2,'medium',1,1,'Why should computer users stay hydrated?','To prevent fatigue and headaches.',1),
(1059,1,1,'mcq','S2/SS2','Lighting',2,'medium',1,1,'Which type of lighting is best for computer use?','Soft, indirect lighting.',1),
(1060,1,1,'mcq','S2/SS2','Monitor Setup',2,'medium',1,1,'Why should glare be minimized on screens?','To reduce eye strain.',1),
(1061,1,1,'mcq','S2/SS2','Work Habits',2,'medium',1,1,'Which habit promotes safe computer use?','Taking scheduled breaks.',1),
(1062,1,1,'mcq','S2/SS2','Cable Safety',2,'medium',1,1,'What is the safest way to handle cables?','Keep them organized and out of walkways.',1),
(1063,1,1,'mcq','S2/SS2','Electrical Safety',2,'medium',1,1,'What should be done before cleaning a computer?','Turn off and unplug it.',1),
(1064,1,1,'mcq','S2/SS2','Fire Safety',2,'medium',1,1,'Which device helps prevent electrical fires?','Surge protector.',1),
(1065,1,1,'mcq','S2/SS2','RSI Prevention',2,'medium',1,1,'Which factor is most important in preventing RSI?','Proper workstation setup.',1),
(1066,1,1,'mcq','S2/SS2','Vision Problems',2,'medium',1,1,'Which symptom indicates eye strain?','Blurred vision.',1),
(1067,1,1,'mcq','S2/SS2','Headaches',2,'medium',1,1,'Which factor can trigger computer-related headaches?','Screen glare.',1),
(1068,1,1,'mcq','S2/SS2','Sleep Disorders',2,'medium',1,1,'What habit improves sleep quality for computer users?','Avoid screens before bedtime.',1),
(1069,1,1,'mcq','S2/SS2','Weight Management',2,'medium',1,1,'Which habit helps prevent weight gain from computer use?','Regular physical activity.',1),
(1070,1,1,'mcq','S2/SS2','Mental Health',2,'medium',1,1,'Which activity helps reduce stress from computer use?','Taking breaks and relaxing.',1),
(1071,1,1,'mcq','S2/SS2','Trips and Falls',2,'medium',1,1,'Which practice reduces fall risks in computer labs?','Proper cable arrangement.',1),
(1072,1,1,'mcq','S2/SS2','Electrocution',2,'medium',1,1,'Which action reduces electrocution risk?','Avoid touching plugs with wet hands.',1),
(1073,1,1,'mcq','S2/SS2','Fire Hazards',2,'medium',1,1,'Which action reduces fire hazards?','Avoid overloading sockets.',1),
(1074,1,1,'mcq','S2/SS2','Safety Awareness',2,'medium',1,1,'Why is safety awareness important in computer labs?','It prevents accidents and injuries.',1);
